import{_ as t}from"./chunks/project-settings_01.CuuUlwv5.js";import{_ as a,o as l,c as o,a2 as i}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Configuración del Proyecto","description":"","frontmatter":{},"headers":[],"relativePath":"es/configuration/project-settings.md","filePath":"es/configuration/project-settings.md"}'),n={name:"es/configuration/project-settings.md"};function r(d,e,s,c,g,m){return l(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="configuracion-del-proyecto" tabindex="-1"><i class="ph-fill ph-gear-six"></i> Configuración del Proyecto <a class="header-anchor" href="#configuracion-del-proyecto" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-gear-six&quot;&gt;&lt;/i&gt; Configuración del Proyecto&quot;">​</a></h1><p>Todos los ajustes globales de WebAP están centralizados en una sola ubicación: <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong></p><p><img src="'+t+'" alt=""></p><h2 id="configuracion-general-general-settings" tabindex="-1">Configuración General (General Settings) <a class="header-anchor" href="#configuracion-general-general-settings" aria-label="Permalink to &quot;Configuración General (General Settings)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Parámetro</th><th style="text-align:left;">Descripción</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Target Min FPS</strong></td><td style="text-align:left;">La línea base de rendimiento. • Si el FPS actual cae por debajo de este valor (teniendo en cuenta el Margen de Rendimiento), el plugin comenzará a reducir la calidad gráfica. • Si el FPS se mantiene consistentemente por encima, el plugin intentará mejorar la calidad. <em>Recomendación:</em> Establece un valor razonable. Para WebGL, el estándar de facto es <code>60</code>, pero para proyectos 3D pesados puedes utilizar <code>30</code>.</td></tr></tbody></table><h2 id="configuracion-del-indexer-indexer-settings" tabindex="-1">Configuración del Indexer (Indexer Settings) <a class="header-anchor" href="#configuracion-del-indexer-indexer-settings" aria-label="Permalink to &quot;Configuración del Indexer (Indexer Settings)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Parámetro</th><th style="text-align:left;">Descripción</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Decrease Cooldown</strong></td><td style="text-align:left;">El tiempo (en segundos) que el sistema espera después de <em>disminuir</em> la calidad antes de reevaluar el FPS. <em>Recomendación:</em> Debe ser corto (<code>1.0</code> - <code>2.0</code> s). El sistema debe responder ágilmente a los retrasos y &quot;soltar lastre&quot; hasta que el FPS se estabilice.</td></tr><tr><td style="text-align:left;"><strong>Increase Cooldown</strong></td><td style="text-align:left;">El tiempo de espera después de <em>aumentar</em> la calidad. <em>Recomendación:</em> Debe ser largo (<code>5.0</code> - <code>10.0</code> s). Antes de sobrecargar el sistema de nuevo, debe verificar que la mejora gráfica previa no haya arruinado la estabilidad del fotograma.</td></tr></tbody></table><h2 id="sistema-de-penalizacion-anti-yo-yo" tabindex="-1">Sistema de Penalización Anti Yo-Yo <a class="header-anchor" href="#sistema-de-penalizacion-anti-yo-yo" aria-label="Permalink to &quot;Sistema de Penalización Anti Yo-Yo&quot;">​</a></h2><p>Previene el &quot;efecto yo-yo&quot;, donde la calidad cambia interminablemente entre dos niveles.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Parámetro</th><th style="text-align:left;">Descripción</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Detection Window</strong></td><td style="text-align:left;">El marco de tiempo después de <em>aumentar</em> la calidad durante el cual el sistema monitorea de cerca el FPS. Si se produce una caída de FPS en este período, el sistema lo clasifica como Efecto Yo-Yo.</td></tr><tr><td style="text-align:left;"><strong>Penalty Lockout Duration</strong></td><td style="text-align:left;">La duración de la penalización (e.g., <code>60</code> s) durante la cual cualquier intento de <em>aumentar</em> la calidad queda categóricamente bloqueado.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Nota</p><p>La penalización bloquea exclusivamente los aumentos. Si el FPS vuelve a caer, el sistema aún puede reducir la calidad en caso de emergencia.</p></div><h2 id="scalers" tabindex="-1">Scalers <a class="header-anchor" href="#scalers" aria-label="Permalink to &quot;Scalers&quot;">​</a></h2><p>Cada Scaler activo posee un conjunto de parámetros de referencia. Estos parámetros dictan su &quot;costo&quot; para el sistema. El plugin calcula automáticamente este costo en tiempo real: el Scaler con el impacto visual más bajo y el Target correspondiente (CPU/GPU) será invocado primero.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Parámetro</th><th style="text-align:left;">Descripción</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Max Level</strong></td><td style="text-align:left;">El número de pasos (niveles) discretos entre la calidad base y la calidad mínima. Por ejemplo, <code>Max Level = 4</code> significa que este Scaler tiene 4 pasos de degradación.</td></tr><tr><td style="text-align:left;"><strong>Min Bound</strong></td><td style="text-align:left;">El valor de escala mínimo (aplicado cuando el Scaler alcanza su <code>Max Level</code>). Por ejemplo, <code>0.5</code> dicta una reducción de calidad al 50% del original.</td></tr><tr><td style="text-align:left;"><strong>Max Bound</strong></td><td style="text-align:left;">El valor de escala máximo. Típicamente igual a <code>1.0</code> (calidad al 100%), este es el valor predeterminado del Nivel 0.</td></tr><tr><td style="text-align:left;"><strong>Visual Impact</strong></td><td style="text-align:left;">El impacto visual en el renderizado (<code>Low</code>, <code>Medium</code>, <code>High</code>). El plugin dará prioridad sistemáticamente al aumento del nivel (disminuyendo la calidad) para los Scalers con impacto <code>Low</code>.</td></tr><tr><td style="text-align:left;"><strong>Target</strong></td><td style="text-align:left;">Especifica qué subsistema optimiza el Scaler (<code>CPU</code>, <code>GPU</code> o ambos). Si el Cuello de Botella (Bottleneck) actual del sistema es la <code>CPU</code>, el plugin ignorará los Scalers de <code>GPU</code>.</td></tr><tr><td style="text-align:left;"><strong>Target Tags</strong></td><td style="text-align:left;">Ciertos Scalers dedicados (<code>WebResolutionScaler</code>, <code>WebCameraClipScaler</code>, <code>WebLayerCullingScaler</code>) aplican su configuración a cámaras específicas en la escena en lugar de globalmente.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Trabajando con Etiquetas de Cámara (Camera Tags)</p><p>Estos Scalers no utilizan una llamada a <code>Camera.main</code>. En su lugar, escanean las cámaras activas utilizando la matriz <code>Target Tags</code>.</p><p>De forma predeterminada, la etiqueta <code>MainCamera</code> se especifica allí. <strong>Si tu juego utiliza etiquetas de cámara personalizadas (por ejemplo, <code>PlayerCamera</code>), debes agregarlas a la configuración del Scaler.</strong> De lo contrario, la escala no se activará en esas cámaras.</p></div><h2 id="configuracion-de-desarrollo-development-settings" tabindex="-1">Configuración de Desarrollo (Development Settings) <a class="header-anchor" href="#configuracion-de-desarrollo-development-settings" aria-label="Permalink to &quot;Configuración de Desarrollo (Development Settings)&quot;">​</a></h2><p>Esta sección está dedicada a depurar el comportamiento del plugin en el navegador o Editor.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Parámetro</th><th style="text-align:left;">Descripción</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Logging</strong></td><td style="text-align:left;">Permite registrar un rastro detallado de las acciones del plugin en la consola del navegador (o Unity). Imprime mensajes sobre los cambios en el Cuello de Botella, la activación de Scalers y el disparo del Sistema de Penalización Anti Yo-Yo.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Optimización</p><p>El registro utiliza contenedores internos <code>DebugWebAP</code>. Se recomienda encarecidamente desactivar el <code>Logging</code> en las builds finales (release) para preservar los recursos y mantener la consola limpia.</p></div>',19)])])}const b=a(n,[["render",r]]);export{f as __pageData,b as default};
